={{ {
  sql: "INSERT INTO event_clusters (topic_slug, date_key, cluster_label, alert_count, importance_score) VALUES (?, ?, ?, 1, ?) ON CONFLICT(topic_slug, date_key, cluster_label) DO UPDATE SET alert_count = alert_count + 1, importance_score = MAX(importance_score, excluded.importance_score), updated_at = strftime('%Y-%m-%dT%H:%M:%SZ', 'now') RETURNING id",
  params: [
    $json.topic_slug,
    $json.date_key,
    $json.cluster_label || $json.topic_slug,
    $json.importance_score
  ]
} }}

