// Extract the cluster_id returned by the upsert.
const d1Response = $input.item.json;
const clusterId = d1Response?.result?.[0]?.results?.[0]?.id || null;
// Pass the cluster_id forward alongside the original alert data
const alert = $('Expand Alerts').item.json;
return [{ json: { ...alert, cluster_id: clusterId } }];

// Extract the D1-assigned alert ID and attach to payload.
const d1Response = $input.item.json;
const alertId = d1Response?.result?.[0]?.results?.[0]?.id || null;
const alert = $('Extract Cluster ID').item.json;
return [{ json: { ...alert, alert_id: alertId } }];

